drop extension if exists "pg_net";


  create table "public"."players" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "first_name" text not null,
    "last_name" text not null,
    "birth_year" bigint not null,
    "birth_month" bigint default '1'::bigint,
    "birth_day" bigint default '1'::bigint,
    "team_id" bigint not null
      );


alter table "public"."players" enable row level security;


  create table "public"."teams" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "team_name" text not null
      );


alter table "public"."teams" enable row level security;


  create table "public"."test_type" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "test_name" character varying not null,
    "category" integer not null
      );


alter table "public"."test_type" enable row level security;


  create table "public"."tests" (
    "id" bigint generated by default as identity not null,
    "created_at" timestamp with time zone not null default now(),
    "seconds" double precision,
    "taken_at" timestamp with time zone not null default now(),
    "player_id" bigint not null,
    "type_id" bigint not null,
    "points" smallint
      );


alter table "public"."tests" enable row level security;

CREATE UNIQUE INDEX players_pkey ON public.players USING btree (id);

CREATE UNIQUE INDEX teams_pkey ON public.teams USING btree (id);

CREATE UNIQUE INDEX test_type_pkey ON public.test_type USING btree (id);

CREATE UNIQUE INDEX tests_pkey ON public.tests USING btree (id);

alter table "public"."players" add constraint "players_pkey" PRIMARY KEY using index "players_pkey";

alter table "public"."teams" add constraint "teams_pkey" PRIMARY KEY using index "teams_pkey";

alter table "public"."test_type" add constraint "test_type_pkey" PRIMARY KEY using index "test_type_pkey";

alter table "public"."tests" add constraint "tests_pkey" PRIMARY KEY using index "tests_pkey";

alter table "public"."players" add constraint "players_team_id_fkey" FOREIGN KEY (team_id) REFERENCES public.teams(id) ON UPDATE RESTRICT ON DELETE RESTRICT not valid;

alter table "public"."players" validate constraint "players_team_id_fkey";

alter table "public"."tests" add constraint "tests_player_id_fkey" FOREIGN KEY (player_id) REFERENCES public.players(id) ON UPDATE CASCADE ON DELETE CASCADE not valid;

alter table "public"."tests" validate constraint "tests_player_id_fkey";

alter table "public"."tests" add constraint "tests_type_id_fkey" FOREIGN KEY (type_id) REFERENCES public.test_type(id) ON UPDATE CASCADE not valid;

alter table "public"."tests" validate constraint "tests_type_id_fkey";

