  create policy "Allow authenticated add players"
  on "public"."players"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Allow authenticated edit players"
  on "public"."players"
  as permissive
  for update
  to authenticated
using (true);



  create policy "Enable read access for authenticated users"
  on "public"."players"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Enable read access for all users"
  on "public"."teams"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Enable read access for all users"
  on "public"."test_type"
  as permissive
  for select
  to public
using (true);



  create policy "Enable insert for authenticated users only"
  on "public"."tests"
  as permissive
  for insert
  to authenticated
with check (true);



  create policy "Enable read access for authenticated users"
  on "public"."tests"
  as permissive
  for select
  to authenticated
using (true);



  create policy "Allow listening for broadcasts for authenticated users only"
  on "realtime"."messages"
  as permissive
  for select
  to authenticated
using ((extension = 'broadcast'::text));



